import React, { useEffect, useState, useCallback } from 'react';
import { useParams, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';
import { formatDistanceToNow } from 'date-fns';
import './MatchedDonors.css';

const URGENCY_BADGE = { critical: 'badge-red', high: 'badge-orange', medium: 'badge-yellow', low: 'badge-green' };

export default function MatchedDonors() {
  const { requestId } = useParams();
  const { user } = useAuth();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [responding, setResponding] = useState({});
  const [error, setError] = useState('');

  const fetchData = useCallback(async () => {
    try {
      const res = await api.get(`/requests/${requestId}/matched-donors`);
      setData(res.data);
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to load matched donors.');
    } finally {
      setLoading(false);
    }
  }, [requestId]);

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 10000);
    return () => clearInterval(interval);
  }, [fetchData]);

  const handleRespond = async (action) => {
    setResponding(r => ({ ...r, [action]: true }));
    try {
      await api.post('/respond-request', { request_id: parseInt(requestId), action });
      await fetchData();
    } catch (err) {
      setError(err.response?.data?.error || 'Failed to respond.');
    } finally {
      setResponding(r => ({ ...r, [action]: false }));
    }
  };

  if (loading) return (
    <div className="page-container" style={{ textAlign: 'center', paddingTop: '4rem' }}>
      <span className="spinner" style={{ width: 36, height: 36 }} />
    </div>
  );

  if (error) return (
    <div className="page-container">
      <div className="alert alert-error">{error}</div>
      <Link to="/dashboard" className="btn btn-secondary">← Back to Dashboard</Link>
    </div>
  );

  const { request, matched_donors } = data || {};

  // Check if current user is a donor and their response
  const myDonorResponse = matched_donors?.find(d => d.email === user?.email)?.response;

  return (
    <div className="page-container">
      <div className="matched-header">
        <Link to="/dashboard" className="back-link">← Dashboard</Link>
        <h1 className="page-title" style={{ marginBottom: 0 }}>Matched Donors</h1>
      </div>

      {/* Request summary */}
      {request && (
        <div className="request-summary card">
          <div className="summary-top">
            <span className="blood-group-badge lg">{request.blood_group}</span>
            <div className="summary-info">
              <h2>{request.patient_name}</h2>
              <p>🏥 {request.hospital_name} · 📍 {request.location}</p>
              <p>📞 {request.contact_number} · {request.units_needed} unit(s) needed</p>
            </div>
            <div className="summary-badges">
              <span className={`badge ${URGENCY_BADGE[request.urgency] || 'badge-gray'}`}>{request.urgency}</span>
              <span className="badge badge-blue">{request.status}</span>
            </div>
          </div>
          <p className="summary-time">
            Created {formatDistanceToNow(new Date(request.created_at), { addSuffix: true })}
          </p>

          {/* Donor response buttons */}
          {user?.role === 'donor' && (
            <div className="donor-response-section">
              <p className="response-prompt">Are you available to donate?</p>
              {myDonorResponse ? (
                <div className={`response-status ${myDonorResponse}`}>
                  {myDonorResponse === 'accepted' ? '✅ You accepted this request' : '❌ You declined this request'}
                </div>
              ) : (
                <div className="response-buttons">
                  <button
                    className="btn btn-success"
                    onClick={() => handleRespond('accepted')}
                    disabled={responding.accepted}
                  >
                    {responding.accepted ? <span className="spinner" /> : '✅ Accept Request'}
                  </button>
                  <button
                    className="btn btn-secondary"
                    onClick={() => handleRespond('declined')}
                    disabled={responding.declined}
                  >
                    {responding.declined ? <span className="spinner" /> : '❌ Decline'}
                  </button>
                </div>
              )}
            </div>
          )}
        </div>
      )}

      {/* Matched donors list */}
      <div className="card" style={{ marginTop: '1.5rem' }}>
        <h2 className="section-title">
          🩸 {matched_donors?.length || 0} Compatible Donor{matched_donors?.length !== 1 ? 's' : ''} Found
        </h2>

        {matched_donors?.length === 0 ? (
          <div className="no-donors">
            <p>No available donors found for blood group <strong>{request?.blood_group}</strong>.</p>
            <p>Notifications have been sent to all compatible donors in the system.</p>
          </div>
        ) : (
          <div className="donors-grid">
            {matched_donors.map(donor => (
              <div key={donor.id} className={`donor-card ${donor.response === 'accepted' ? 'accepted' : donor.response === 'declined' ? 'declined' : ''}`}>
                <div className="donor-card-top">
                  <span className="blood-group-badge">{donor.blood_group}</span>
                  {donor.response === 'accepted' && <span className="badge badge-green">✅ Accepted</span>}
                  {donor.response === 'declined' && <span className="badge badge-gray">❌ Declined</span>}
                  {!donor.response && <span className="badge badge-blue">Pending</span>}
                </div>
                <h3 className="donor-name">{donor.name}</h3>
                <div className="donor-details">
                  <span>📍 {donor.location || 'Location not set'}</span>
                  <span>📞 {donor.phone || 'N/A'}</span>
                  {donor.distance_km !== null && (
                    <span className="distance">📏 {donor.distance_km} km away</span>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
